#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
const int dx[] = {1, 1, 2, 2, -1, -1, -2, -2}, dy[] = {2, -2, 1, -1, 2, -2, 1, -1}, MAXN = 5e2 + 5;
struct pos
{
	int x, y, ans;
	pos(int a, int b, int c)
	{
		x = a, y = b, ans = c;
	}
};
int n, m, x, y, c[MAXN][MAXN];
bool vis[MAXN][MAXN];
void bfs()
{
	queue<pos>q;
	q.push(pos(x, y, 0));
	while (!q.empty())
	{
		pos now = q.front();
		q.pop();
		int x = now.x, y = now.y, ans = now.ans;
		if (x < 1 || x > n || y < 1 || y > m || vis[x][y])continue;
		vis[x][y] = true, c[x][y] = ans;
		for (int i = 0; i < 8; ++i)q.push(pos(x + dx[i], y + dy[i], ans + 1));
	}
}
int main(void)
{
	memset(c, -1, sizeof(c));
	scanf("%d%d%d%d", &n, &m, &x, &y);
	bfs();
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= m; ++j)printf("%-5d", c[i][j]);
		putchar('\n');
	}
	return false;
}
